import{_ as a,o as r,c as o,ai as e}from"./chunks/framework.SowO7O0D.js";const u=JSON.parse('{"title":"第二十课：下单与成交","description":"","frontmatter":{},"headers":[],"relativePath":"guide/20-order-execution.md","filePath":"guide/20-order-execution.md","lastUpdated":0}'),l={name:"guide/20-order-execution.md"};function i(d,t,n,h,s,c){return r(),o("div",null,[...t[0]||(t[0]=[e('<h1 id="第二十课-下单与成交" tabindex="-1">第二十课：下单与成交 <a class="header-anchor" href="#第二十课-下单与成交" aria-label="Permalink to “第二十课：下单与成交”">​</a></h1><p>这是入门教程的最后一课，讲解实际买卖股票的操作流程。</p><h2 id="一、下单方式" tabindex="-1">一、下单方式 <a class="header-anchor" href="#一、下单方式" aria-label="Permalink to “一、下单方式”">​</a></h2><h3 id="_1-市价单" tabindex="-1">1. 市价单 <a class="header-anchor" href="#_1-市价单" aria-label="Permalink to “1. 市价单”">​</a></h3><p>以当前市场价格立即成交。</p><p><strong>优点</strong>：保证成交 <strong>缺点</strong>：成交价格不确定（尤其是波动大的时候）</p><h3 id="_2-限价单" tabindex="-1">2. 限价单 <a class="header-anchor" href="#_2-限价单" aria-label="Permalink to “2. 限价单”">​</a></h3><p>设定一个价格，只有达到这个价格才成交。</p><p><strong>优点</strong>：价格确定 <strong>缺点</strong>：可能成交不了</p><blockquote><p>💡 <strong>建议新手用限价单</strong>，特别是A股有涨跌停限制，不会差太多。</p></blockquote><h2 id="二、a股交易费用" tabindex="-1">二、A股交易费用 <a class="header-anchor" href="#二、a股交易费用" aria-label="Permalink to “二、A股交易费用”">​</a></h2><table tabindex="0"><thead><tr><th>费用项目</th><th>收费标准</th><th>收取方式</th></tr></thead><tbody><tr><td>印花税</td><td>0.05%</td><td>卖出时收取（国家）</td></tr><tr><td>过户费</td><td>0.001%</td><td>买卖双向（交易所）</td></tr><tr><td>佣金</td><td>万1-万3</td><td>买卖双向（券商）</td></tr></tbody></table><blockquote><p>💡 现在佣金普遍很低，开户可以跟客户经理谈，降低交易成本。</p></blockquote><h2 id="三、买入实操步骤" tabindex="-1">三、买入实操步骤 <a class="header-anchor" href="#三、买入实操步骤" aria-label="Permalink to “三、买入实操步骤”">​</a></h2><p>以券商APP为例（涨乐财富通）：</p><ol><li><strong>打开APP</strong> → 点&quot;交易&quot;</li><li><strong>点击&quot;买入&quot;</strong></li><li><strong>输入股票代码</strong>（如600519）</li><li><strong>输入买入价格</strong>（限价单需要填写）</li><li><strong>输入买入数量</strong>（100股=1手）</li><li><strong>确认买入</strong></li><li><strong>输入交易密码</strong></li><li><strong>下单成功</strong></li></ol><h2 id="四、卖出实操步骤" tabindex="-1">四、卖出实操步骤 <a class="header-anchor" href="#四、卖出实操步骤" aria-label="Permalink to “四、卖出实操步骤”">​</a></h2><ol><li><strong>点击&quot;持仓&quot;</strong></li><li><strong>选择要卖的股票</strong></li><li><strong>点击&quot;卖出&quot;</strong></li><li><strong>填写卖出价格和数量</strong></li><li><strong>确认卖出</strong></li></ol><h2 id="五、成交规则" tabindex="-1">五、成交规则 <a class="header-anchor" href="#五、成交规则" aria-label="Permalink to “五、成交规则”">​</a></h2><p>股票成交遵循两个原则：</p><table tabindex="0"><thead><tr><th>原则</th><th>说明</th></tr></thead><tbody><tr><td><strong>价格优先</strong></td><td>买的时候，出价高的先成交；卖的时候，出价低的先成交</td></tr><tr><td><strong>时间优先</strong></td><td>价格相同时，先挂单的先成交</td></tr></tbody></table><h3 id="涨停板时怎么成交" tabindex="-1">涨停板时怎么成交？ <a class="header-anchor" href="#涨停板时怎么成交" aria-label="Permalink to “涨停板时怎么成交？”">​</a></h3><p>如果一只股票涨停了，你想买进：</p><ul><li>按&quot;价格优先&quot;，你的买入价必须≥涨停价</li><li>按&quot;时间优先&quot;，你挂单越早，成交机会越大</li></ul><blockquote><p>所以涨停板买不进是常态，第二天开盘也不一定涨。</p></blockquote><h2 id="六、常见问题处理" tabindex="-1">六、常见问题处理 <a class="header-anchor" href="#六、常见问题处理" aria-label="Permalink to “六、常见问题处理”">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>解决方案</th></tr></thead><tbody><tr><td>下单提示&quot;资金不足&quot;</td><td>账户里钱不够，需要银证转账</td></tr><tr><td>下单提示&quot;股票停牌&quot;</td><td>停牌期间无法交易，等复牌</td></tr><tr><td>卖出提示&quot;持仓不足&quot;</td><td>你没持有那么多股票</td></tr><tr><td>成交了但看不到</td><td>持仓更新有延迟，等1-2分钟</td></tr><tr><td>想撤单怎么撤</td><td>在&quot;当日委托&quot;里找&quot;撤单&quot;</td></tr></tbody></table><h2 id="七、银证转账" tabindex="-1">七、银证转账 <a class="header-anchor" href="#七、银证转账" aria-label="Permalink to “七、银证转账”">​</a></h2><p>买股票之前，钱要从银行卡转到证券账户：</p><ol><li>打开券商APP → &quot;交易&quot; → &quot;银证转账&quot;</li><li>选择&quot;转入&quot;</li><li>输入金额</li><li>确认</li></ol><blockquote><p>💡 建议：<strong>收盘后把多余的钱转回银行卡</strong>，控制冲动交易。</p></blockquote><h2 id="八、新手第一单的注意事项" tabindex="-1">八、新手第一单的注意事项 <a class="header-anchor" href="#八、新手第一单的注意事项" aria-label="Permalink to “八、新手第一单的注意事项”">​</a></h2><blockquote><p>🚨 <strong>第一笔交易要谨慎！</strong></p></blockquote><ol><li>不要一次满仓，先买1手试试</li><li>选择波动适中的股票</li><li>设置好止损价</li><li>记录买卖理由</li><li>亏损了不要急着补仓</li></ol><h2 id="恭喜你" tabindex="-1">恭喜你！ <a class="header-anchor" href="#恭喜你" aria-label="Permalink to “恭喜你！”">​</a></h2><p>学完这20课，你已经掌握了A股投资的基础知识。</p><h2 id="入门不是终点" tabindex="-1">入门不是终点 <a class="header-anchor" href="#入门不是终点" aria-label="Permalink to “入门不是终点”">​</a></h2><p><strong>这只是开始。</strong> 真正能在股市赚到钱，还需要：</p><ul><li>✅ 持续学习的心态</li><li>✅ 控制情绪的能力</li><li>✅ 严格执行的纪律</li><li>✅ 长期坚持的耐心</li></ul><h2 id="最后的话" tabindex="-1">最后的话 <a class="header-anchor" href="#最后的话" aria-label="Permalink to “最后的话”">​</a></h2><blockquote><p>股市有风险，入市需谨慎。 不要用急用的钱炒股。 不要杠杆炒股。 永远敬畏市场。</p></blockquote><p><strong>祝你在股市里稳健前行！</strong> 📈</p><hr><p><em>本教程由 A股学习站 自动生成，每日日报同步更新。</em></p>',44)])])}const g=a(l,[["render",i]]);export{u as __pageData,g as default};
